class RapidDeckPage extends StatefulWidget {
  const RapidDeckPage({super.key});

  @override
  State<RapidDeckPage> createState() => _RapidDeckPageState();
}

class _ThreeDDeckCard extends StatefulWidget {
  final Widget child;
  final int index;
  final _MotionTier tier;
  final double cinematicIntensity;
  final int styleSeed;
  final int reactionNonce;
  final _RapidRarity rarity;

  const _ThreeDDeckCard({
    required this.child,
    required this.index,
    required this.tier,
    this.cinematicIntensity = 1,
    this.styleSeed = 0,
    this.reactionNonce = 0,
    this.rarity = _RapidRarity.common,
  });

  @override
  State<_ThreeDDeckCard> createState() => _ThreeDDeckCardState();
}

class _ThreeDDeckCardState extends State<_ThreeDDeckCard>
    with SingleTickerProviderStateMixin {
  late final AnimationController _floatController;
  late final AnimationController _reactionController;
  static const List<Color> _accentPalette = [
    Color(0xFF68D4FF),
    Color(0xFFB59BFF),
    Color(0xFF67F2CC),
    Color(0xFFFFC386),
    Color(0xFF8AA8FF),
    Color(0xFFFF88C7),
  ];

  double _unitFromHash(int salt) {
    final x = (widget.index + 1) * 1103515245 + (widget.styleSeed + salt) * 12345;
    final v = ((x ^ (x >> 16)) & 0x7fffffff) / 0x7fffffff;
    return v.clamp(0.0, 1.0);
  }

  @override
  void initState() {
    super.initState();
    final tempoSeed = (((widget.index + 1) * 73) + (widget.styleSeed * 19)) % 1200;
    _floatController = AnimationController(
      vsync: this,
      duration: Duration(milliseconds: 1800 + tempoSeed),
    );
    if (widget.tier == _MotionTier.cinematic) {
      _floatController.repeat(reverse: true);
    }
    _reactionController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 900),
    );
  }

  @override
  void didUpdateWidget(covariant _ThreeDDeckCard oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.tier != widget.tier) {
      if (widget.tier == _MotionTier.cinematic) {
        _floatController.repeat(reverse: true);
      } else {
        _floatController
          ..stop()
          ..value = 0;
      }
    }
    if (oldWidget.reactionNonce != widget.reactionNonce) {
      _reactionController
        ..stop()
        ..forward(from: 0);
    }
  }

  @override
  void dispose() {
    _floatController.dispose();
    _reactionController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final cinematicIntensity =
        widget.cinematicIntensity.clamp(0.6, 1.8).toDouble();
    final profileA = _unitFromHash(7);
    final profileB = _unitFromHash(23);
    final profileC = _unitFromHash(59);
    final variant = ((profileA * 1000).floor() + (profileB * 137).floor()) % 6;
    final accent = _accentPalette[((profileC * 1000).floor()) % _accentPalette.length];
    final perspective = widget.tier == _MotionTier.low
        ? 0.0006
        : widget.tier == _MotionTier.balanced
            ? 0.0012
            : 0.0021 * cinematicIntensity;
    final introRotateX = widget.tier == _MotionTier.low
        ? 0.04
        : widget.tier == _MotionTier.balanced
            ? 0.095
            : (0.08 + (profileA * 0.1)) * cinematicIntensity;
    final introRotateY = widget.tier == _MotionTier.low
        ? -0.015
        : widget.tier == _MotionTier.balanced
            ? -0.03
            : ((profileB - 0.5) * 0.13) * cinematicIntensity;
    final maxTilt = widget.tier == _MotionTier.low
        ? 0.045
        : widget.tier == _MotionTier.balanced
            ? 0.08
            : 0.12 * cinematicIntensity;
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0, end: 1),
      duration: Duration(milliseconds: 220 + (profileA * 240).round()),
      curve: Curves.easeOutCubic,
      builder: (context, t, child) {
        final depth = (1 - t);
        final intro = Matrix4.identity()
          ..setEntry(3, 2, perspective)
          ..translate(0.0, 16 * depth, 0.0)
          ..rotateX(introRotateX * depth)
          ..rotateY(introRotateY * depth);
        return Opacity(
          opacity: t,
          child: Transform(
            transform: intro,
            alignment: Alignment.center,
            child: child,
          ),
        );
      },
      child: AnimatedBuilder(
        animation: Listenable.merge([_floatController, _reactionController]),
        builder: (context, child) {
          final phaseA = profileA * math.pi * 2;
          final phaseB = profileB * math.pi * 2;
          final speedA = 1.0 + (profileA * 1.8);
          final speedB = 0.8 + (profileC * 2.2);
          final t = _floatController.value * math.pi * 2;
          final wave = math.sin((t * speedA) + phaseA);
          final waveB = math.cos((t * speedB) + phaseB);
          final baseLift = widget.tier == _MotionTier.cinematic
              ? 3.0 * cinematicIntensity
              : widget.tier == _MotionTier.balanced
                  ? 1.2
                  : 0.0;
          final lift = ((wave * (0.5 + profileA)) + (waveB * (0.2 + profileB))) *
              (baseLift * (0.55 + profileC * 0.65));
          final spinY = (wave * (0.012 + profileB * 0.05)) *
              (widget.tier == _MotionTier.low
                  ? 0.65
                  : widget.tier == _MotionTier.balanced
                      ? 1.0
                      : cinematicIntensity);
          final nodX = (waveB * (0.009 + profileC * 0.03)) *
              (widget.tier == _MotionTier.low
                  ? 0.55
                  : widget.tier == _MotionTier.balanced
                      ? 0.9
                      : cinematicIntensity);
          final pulseScale = 1.0 +
              ((wave * (0.004 + profileA * 0.008)) +
                      (waveB * (0.003 + profileB * 0.006))) *
                  (widget.tier == _MotionTier.low ? 0.55 : 1.0) *
                  cinematicIntensity;
          final skewX = (profileB - 0.5) * 0.0009;
          final skewY = (profileC - 0.5) * 0.0011;
          final shadowAlpha = widget.tier == _MotionTier.cinematic
              ? (0.24 +
                      (((wave.abs() + waveB.abs()) * 0.5) *
                          0.09 *
                          cinematicIntensity))
                  .clamp(0.2, 0.42)
              : 0.18;
          final r = Curves.easeOutCubic.transform(_reactionController.value);
          final rx = ((_unitFromHash(widget.reactionNonce + 101) * 2) - 1);
          final ry = ((_unitFromHash(widget.reactionNonce + 211) * 2) - 1);
          final reactShift = switch (widget.rarity) {
            _RapidRarity.common => Offset(0, -10 * math.sin(r * math.pi)),
            _RapidRarity.rare => Offset(rx * 16 * (1 - r), ry * 10 * (1 - r)),
            _RapidRarity.epic => Offset(rx * 28 * (1 - r), ry * 18 * (1 - r)),
            _RapidRarity.legendary =>
              Offset(rx * 56 * (1 - r), ry * 26 * (1 - r)),
          };
          final reactRoll = switch (widget.rarity) {
            _RapidRarity.common => 0.0,
            _RapidRarity.rare => (1 - r) * (math.pi * 0.7) * (rx.sign == 0 ? 1 : rx.sign),
            _RapidRarity.epic => (1 - r) * (math.pi * 1.1) * (rx.sign == 0 ? 1 : rx.sign),
            _RapidRarity.legendary => (1 - r) * (math.pi * 1.6) * (rx.sign == 0 ? 1 : rx.sign),
          };
          final reactScale = switch (widget.rarity) {
            _RapidRarity.common => 1 + (0.03 * math.sin(r * math.pi)),
            _RapidRarity.rare => 1 + (0.06 * math.sin(r * math.pi)),
            _RapidRarity.epic => 1 + (0.1 * math.sin(r * math.pi)),
            _RapidRarity.legendary => 1 + (0.14 * math.sin(r * math.pi)),
          };
          final shellTransform = Matrix4.identity()
            ..setEntry(3, 2, perspective)
            ..translate(reactShift.dx, -lift + reactShift.dy, 0.0)
            ..rotateY(spinY)
            ..rotateX(nodX)
            ..rotateZ(reactRoll)
            ..setEntry(0, 1, skewX)
            ..setEntry(1, 0, skewY)
            ..scale(pulseScale * reactScale, pulseScale * reactScale);
          return Transform(
            alignment: Alignment.center,
            transform: shellTransform,
            child: DecoratedBox(
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(14),
                boxShadow: [
                  BoxShadow(
                    color: accent.withValues(alpha: shadowAlpha),
                    blurRadius: widget.tier == _MotionTier.cinematic
                        ? 22 * cinematicIntensity
                        : 14,
                    spreadRadius: 0.5,
                    offset: const Offset(0, 8),
                  ),
                ],
              ),
              child: Stack(
                fit: StackFit.passthrough,
                clipBehavior: Clip.none,
                children: [
                  child!,
                  if (widget.rarity == _RapidRarity.epic &&
                      _reactionController.value > 0)
                    Positioned(
                      right: -8 + ((1 - r) * 28),
                      top: -6,
                      child: Transform.rotate(
                        angle: (1 - r) * math.pi,
                        child: Container(
                          width: 22 + (18 * r),
                          height: 22 + (18 * (1 - r)),
                          decoration: BoxDecoration(
                            color: accent.withValues(alpha: 0.22),
                            borderRadius: BorderRadius.circular(12 * r),
                            border: Border.all(
                              color: accent.withValues(alpha: 0.9),
                            ),
                          ),
                        ),
                      ),
                    ),
                  if (widget.rarity == _RapidRarity.legendary &&
                      _reactionController.value > 0)
                    Positioned(
                      left: -18 + ((r) * 230 * rx.sign),
                      top: 8 + ((1 - r) * 18 * ry.sign),
                      child: Transform.rotate(
                        angle: rx * 0.8,
                        child: Icon(
                          (_unitFromHash(widget.reactionNonce + 333) > 0.5)
                              ? Icons.flight
                              : Icons.pets,
                          color: const Color(0xFFFFD166),
                          size: 20 + (8 * (1 - r)),
                        ),
                      ),
                    ),
                  IgnorePointer(
                    child: DecoratedBox(
                      decoration: BoxDecoration(
                        borderRadius: BorderRadius.circular(14),
                        border: Border.all(
                          color: accent.withValues(
                            alpha: widget.tier == _MotionTier.low ? 0.18 : 0.28,
                          ),
                        ),
                        gradient: LinearGradient(
                          begin: Alignment.topLeft,
                          end: Alignment.bottomRight,
                          colors: [
                            accent.withValues(alpha: 0.06),
                            Colors.transparent,
                            accent.withValues(alpha: 0.04),
                          ],
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),
          );
        },
        child: _TiltPanel(
          maxTilt: maxTilt,
          duration: const Duration(milliseconds: 140),
          child: widget.child,
        ),
      ),
    );
  }
}

class _RapidDeckFlipCard extends StatefulWidget {
  final Widget front;
  final Widget back;
  final VoidCallback? onTapReact;

  const _RapidDeckFlipCard({
    required this.front,
    required this.back,
    this.onTapReact,
  });

  @override
  State<_RapidDeckFlipCard> createState() => _RapidDeckFlipCardState();
}

class _RapidDeckFlipCardState extends State<_RapidDeckFlipCard> {
  bool _flipped = false;

  @override
  Widget build(BuildContext context) {
    return InkWell(
      borderRadius: BorderRadius.circular(12),
      onTap: () {
        widget.onTapReact?.call();
      },
      onDoubleTap: () {
        setState(() {
          _flipped = !_flipped;
        });
      },
      child: AnimatedSwitcher(
        duration: const Duration(milliseconds: 320),
        switchInCurve: Curves.easeOutCubic,
        switchOutCurve: Curves.easeInCubic,
        transitionBuilder: (child, animation) {
          final rotate = Tween<double>(begin: math.pi * 0.5, end: 0.0)
              .animate(animation);
          return AnimatedBuilder(
            animation: rotate,
            child: child,
            builder: (context, c) {
              final isUnder = (ValueKey(_flipped) != c?.key);
              var tilt = (animation.value - 0.5).abs() - 0.5;
              tilt *= isUnder ? -0.004 : 0.004;
              final value = isUnder ? math.min(rotate.value, math.pi / 2) : rotate.value;
              return Transform(
                alignment: Alignment.center,
                transform: Matrix4.identity()
                  ..setEntry(3, 2, 0.002)
                  ..rotateY(value)
                  ..setEntry(3, 0, tilt),
                child: c,
              );
            },
          );
        },
        child: KeyedSubtree(
          key: ValueKey<bool>(_flipped),
          child: _flipped ? widget.back : widget.front,
        ),
      ),
    );
  }
}

class _RapidDeckParallaxBackground extends StatelessWidget {
  final ScrollController controller;
  final _MotionTier tier;

  const _RapidDeckParallaxBackground({
    required this.controller,
    required this.tier,
  });

  @override
  Widget build(BuildContext context) {
    return IgnorePointer(
      child: AnimatedBuilder(
        animation: controller,
        builder: (context, child) {
          final y = controller.hasClients ? controller.offset : 0.0;
          final strength = tier == _MotionTier.low
              ? 0.25
              : tier == _MotionTier.cinematic
                  ? 1.0
                  : 0.6;
          final shiftA = (y * 0.04) * strength;
          final shiftB = (y * 0.08) * strength;
          return Stack(
            children: [
              Positioned.fill(
                child: DecoratedBox(
                  decoration: BoxDecoration(
                    gradient: LinearGradient(
                      begin: Alignment.topCenter,
                      end: Alignment.bottomCenter,
                      colors: [
                        const Color(0xFF08111F),
                        const Color(0xFF0D1A2D).withValues(alpha: 0.95),
                        const Color(0xFF101E33),
                      ],
                    ),
                  ),
                ),
              ),
              Positioned(
                left: -90,
                top: -120 + shiftA,
                child: Transform.rotate(
                  angle: -0.16,
                  child: Container(
                    width: 300,
                    height: 300,
                    decoration: BoxDecoration(
                      shape: BoxShape.circle,
                      color: const Color(0xFF53C3FF).withValues(alpha: 0.09),
                    ),
                  ),
                ),
              ),
              Positioned(
                right: -70,
                bottom: -140 - shiftB,
                child: Transform.rotate(
                  angle: 0.24,
                  child: Container(
                    width: 260,
                    height: 260,
                    decoration: BoxDecoration(
                      shape: BoxShape.circle,
                      color: const Color(0xFF7FF6CC).withValues(alpha: 0.08),
                    ),
                  ),
                ),
              ),
            ],
          );
        },
      ),
    );
  }
}

class _RapidDeckPageState extends State<RapidDeckPage> {
  final TextEditingController _searchController = TextEditingController();
  final ScrollController _scrollController = ScrollController();
  final PageController _carouselController =
      PageController(viewportFraction: 0.8);
  String _query = '';
  int _visibleLimit = 48;
  int _rangeFilter = 0;
  int _flipTick = 0;
  double _carouselPage = 0;
  double _cinematicIntensity = 1.0;
  int _styleSeed = 0;
  final Set<int> _favoriteIndexes = <int>{};
  final Map<int, int> _reactionNonceByIndex = <int, int>{};
  bool _favoritesOnly = false;
  bool _spotlightAutoPlay = false;
  Timer? _spotlightTimer;

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_handleScroll);
    _carouselController.addListener(_handleCarousel);
  }

  @override
  void dispose() {
    _searchController.dispose();
    _carouselController
      ..removeListener(_handleCarousel)
      ..dispose();
    _spotlightTimer?.cancel();
    _scrollController
      ..removeListener(_handleScroll)
      ..dispose();
    super.dispose();
  }

  void _toggleSpotlight(bool enabled, List<int> carouselIndexes) {
    _spotlightTimer?.cancel();
    _spotlightTimer = null;
    if (!enabled || carouselIndexes.isEmpty) {
      return;
    }
    _spotlightTimer = Timer.periodic(const Duration(seconds: 3), (_) {
      if (!_carouselController.hasClients || carouselIndexes.isEmpty) {
        return;
      }
      final next = ((_carouselPage.round() + 1) % carouselIndexes.length);
      _carouselController.animateToPage(
        next,
        duration: const Duration(milliseconds: 480),
        curve: Curves.easeOutCubic,
      );
    });
  }

  ({String label, Color color, _RapidRarity rarity}) _rarityForIndex(int index) {
    final mod = (index + _styleSeed) % 100;
    if (mod >= 96) {
      return (
        label: 'Legendary',
        color: const Color(0xFFFFD166),
        rarity: _RapidRarity.legendary
      );
    }
    if (mod >= 84) {
      return (
        label: 'Epic',
        color: const Color(0xFFC9A7FF),
        rarity: _RapidRarity.epic
      );
    }
    if (mod >= 60) {
      return (
        label: 'Rare',
        color: const Color(0xFF85D8FF),
        rarity: _RapidRarity.rare
      );
    }
    return (
      label: 'Common',
      color: const Color(0xFF8CE3BD),
      rarity: _RapidRarity.common
    );
  }

  void _handleCarousel() {
    if (!_carouselController.hasClients || !mounted) {
      return;
    }
    final page =
        _carouselController.page ?? _carouselController.initialPage.toDouble();
    if ((page - _carouselPage).abs() >= 0.001) {
      setState(() {
        _carouselPage = page;
      });
    }
  }

  void _handleScroll() {
    final pos = _scrollController.position;
    if (!pos.hasPixels || !pos.hasContentDimensions) {
      return;
    }
    if (pos.pixels >= pos.maxScrollExtent - 320) {
      final maxItems = rapidDeckBuilders.length;
      if (_visibleLimit < maxItems) {
        setState(() {
          _visibleLimit = math.min(_visibleLimit + 36, maxItems);
        });
      }
    }
  }

  bool _matchesIndex(int index) {
    final q = _query.trim().toLowerCase();
    if (q.isEmpty) {
      return true;
    }
    final label = (index + 1).toString().padLeft(3, '0');
    return label.contains(q) || 'scenario $label'.contains(q);
  }

  bool _matchesRange(int index) {
    switch (_rangeFilter) {
      case 1:
        return index < 100;
      case 2:
        return index >= 100 && index < 200;
      case 3:
        return index >= 200 && index < 300;
      case 4:
        return index >= 300 && index < 400;
      default:
        return true;
    }
  }

  String get _rangeLabel {
    switch (_rangeFilter) {
      case 1:
        return '001-100';
      case 2:
        return '101-200';
      case 3:
        return '201-300';
      case 4:
        return '301-400';
      default:
        return 'All';
    }
  }

  @override
  Widget build(BuildContext context) {
    final all = List<int>.generate(rapidDeckBuilders.length, (i) => i)
        .where(_matchesIndex)
        .where(_matchesRange)
        .where((i) => !_favoritesOnly || _favoriteIndexes.contains(i))
        .toList(growable: false);
    final shown = all.take(_visibleLimit).toList(growable: false);
    final tier = _motionTierFor(context);
    final cinematicIntensity = _cinematicIntensity.clamp(0.6, 1.8).toDouble();
    final carouselIndexes =
        all.take(math.min(10, all.length)).toList(growable: false);
    if (_spotlightAutoPlay && _spotlightTimer == null && carouselIndexes.isNotEmpty) {
      _toggleSpotlight(true, carouselIndexes);
    } else if ((!_spotlightAutoPlay || carouselIndexes.isEmpty) &&
        _spotlightTimer != null) {
      _toggleSpotlight(false, carouselIndexes);
    }

    return Scaffold(
      appBar: AppBar(title: const Text('Rapid Deck')),
      body: Stack(
        children: [
          Positioned.fill(
            child: _RapidDeckParallaxBackground(
              controller: _scrollController,
              tier: tier,
            ),
          ),
          ListView(
            controller: _scrollController,
            padding: const EdgeInsets.all(12),
            children: [
              _CinematicFaceHeader(
                title: 'Rapid Growth Deck',
                subtitle: 'Generated showcase widgets for speed demos',
                tags: [
                  _HeaderTag(
                    icon: Icons.layers,
                    label: '${rapidDeckBuilders.length} cards',
                    tint: const Color(0xFF86D8FF),
                  ),
                  _HeaderTag(
                    icon: Icons.filter_alt,
                    label: '${shown.length}/${all.length} visible',
                    tint: tier == _MotionTier.low
                        ? const Color(0xFF9FB8FF)
                        : const Color(0xFF8AF0C8),
                  ),
                  _HeaderTag(
                    icon: Icons.category,
                    label: 'Range $_rangeLabel',
                    tint: const Color(0xFF9FC3FF),
                  ),
                ],
              ),
              const SizedBox(height: 10),
              if (carouselIndexes.isNotEmpty) ...[
                const Text(
                  'Top 10 Perspective Carousel',
                  style: TextStyle(
                    color: Color(0xFFCDE4FF),
                    fontWeight: FontWeight.w700,
                  ),
                ),
                const SizedBox(height: 8),
                SizedBox(
                  height: 220,
                  child: PageView.builder(
                    controller: _carouselController,
                    itemCount: carouselIndexes.length,
                    itemBuilder: (context, pageIndex) {
                      final index = carouselIndexes[pageIndex];
                      final delta = (pageIndex - _carouselPage).toDouble();
                      final absDelta = delta.abs().clamp(0.0, 1.4);
                      final scale = 1 - (absDelta * 0.12);
                      final angle = delta *
                          (tier == _MotionTier.low
                              ? 0.18
                              : tier == _MotionTier.balanced
                                  ? 0.34
                                  : 0.5 * cinematicIntensity);
                      final zLift = (1 - absDelta) *
                          (tier == _MotionTier.low
                              ? 10
                              : tier == _MotionTier.balanced
                                  ? 18
                                  : 34 * cinematicIntensity);
                      return Transform(
                        alignment: Alignment.center,
                        transform: Matrix4.identity()
                          ..setEntry(
                              3,
                              2,
                              tier == _MotionTier.low
                                  ? 0.0007
                                  : tier == _MotionTier.balanced
                                      ? 0.0015
                                      : 0.0024 * cinematicIntensity)
                          ..translate(0.0, absDelta * 18, zLift)
                          ..rotateY(angle)
                          ..scale(scale, scale),
                        child: Padding(
                          padding: const EdgeInsets.symmetric(horizontal: 6),
                          child: _ThreeDDeckCard(
                            index: index,
                            tier: tier,
                            cinematicIntensity: cinematicIntensity,
                            styleSeed: _styleSeed,
                            reactionNonce: _reactionNonceByIndex[index] ?? 0,
                            rarity: _rarityForIndex(index).rarity,
                            child: Card(
                              color: const Color(0xFF10223A),
                              child: Padding(
                                padding: const EdgeInsets.all(10),
                                child: rapidDeckBuilders[index](),
                              ),
                            ),
                          ),
                        ),
                      );
                    },
                  ),
                ),
                const SizedBox(height: 10),
              ],
              TextField(
                controller: _searchController,
                decoration: const InputDecoration(
                  labelText: 'Filter by number (example: 007, 120)',
                  prefixIcon: Icon(Icons.search),
                ),
                onChanged: (value) {
                  setState(() {
                    _query = value;
                    _visibleLimit = 48;
                  });
                },
              ),
              const SizedBox(height: 10),
              SegmentedButton<int>(
                segments: const [
                  ButtonSegment<int>(value: 0, label: Text('All')),
                  ButtonSegment<int>(value: 1, label: Text('001-100')),
                  ButtonSegment<int>(value: 2, label: Text('101-200')),
                  ButtonSegment<int>(value: 3, label: Text('201-300')),
                  ButtonSegment<int>(value: 4, label: Text('301-400')),
                ],
                selected: {_rangeFilter},
                showSelectedIcon: false,
                onSelectionChanged: (selected) {
                  setState(() {
                    _rangeFilter = selected.first;
                    _visibleLimit = 48;
                    _flipTick += 1;
                  });
                  if (_carouselController.hasClients) {
                    _carouselController.animateToPage(
                      0,
                      duration: const Duration(milliseconds: 260),
                      curve: Curves.easeOutCubic,
                    );
                  }
                },
              ),
              const SizedBox(height: 10),
              Row(
                children: [
                  Expanded(
                    child: OutlinedButton.icon(
                      onPressed: () {
                        setState(() {
                          _styleSeed = (_styleSeed + 1) % 1000;
                          _flipTick += 1;
                        });
                      },
                      icon: const Icon(Icons.auto_fix_high),
                      label: const Text('Shuffle 3D Styles'),
                    ),
                  ),
                  const SizedBox(width: 8),
                  OutlinedButton.icon(
                    onPressed: carouselIndexes.isEmpty
                        ? null
                        : () {
                            final now = DateTime.now();
                            final target =
                                (now.millisecond + now.second) % carouselIndexes.length;
                            _carouselController.animateToPage(
                              target,
                              duration: const Duration(milliseconds: 420),
                              curve: Curves.easeOutCubic,
                            );
                          },
                    icon: const Icon(Icons.casino),
                    label: const Text('Surprise'),
                  ),
                ],
              ),
              const SizedBox(height: 10),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: [
                  FilterChip(
                    selected: _favoritesOnly,
                    onSelected: (v) {
                      setState(() {
                        _favoritesOnly = v;
                        _visibleLimit = 48;
                      });
                    },
                    avatar: const Icon(Icons.star, size: 16),
                    label: Text(
                      _favoritesOnly
                          ? 'Favorites Only (${_favoriteIndexes.length})'
                          : 'Show Favorites (${_favoriteIndexes.length})',
                    ),
                  ),
                  FilterChip(
                    selected: _spotlightAutoPlay,
                    onSelected: (v) {
                      setState(() {
                        _spotlightAutoPlay = v;
                      });
                      _toggleSpotlight(v, carouselIndexes);
                    },
                    avatar: const Icon(Icons.play_circle_fill, size: 16),
                    label: Text(_spotlightAutoPlay
                        ? 'Spotlight Auto-Play On'
                        : 'Spotlight Auto-Play'),
                  ),
                ],
              ),
              const SizedBox(height: 10),
              if (tier == _MotionTier.cinematic) ...[
                Card(
                  color: const Color(0xFF13253D),
                  child: Padding(
                    padding: const EdgeInsets.symmetric(
                        horizontal: 12, vertical: 10),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Row(
                          children: [
                            const Icon(Icons.tune, color: Color(0xFF97DEFF)),
                            const SizedBox(width: 8),
                            Text(
                              'Cinematic Intensity ${cinematicIntensity.toStringAsFixed(2)}x',
                              style: const TextStyle(
                                color: Color(0xFFE7F3FF),
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                            const Spacer(),
                            TextButton(
                              onPressed: () {
                                setState(() {
                                  _cinematicIntensity = 1.0;
                                });
                              },
                              child: const Text('Reset'),
                            ),
                          ],
                        ),
                        Slider(
                          value: cinematicIntensity,
                          min: 0.6,
                          max: 1.8,
                          divisions: 24,
                          label: '${cinematicIntensity.toStringAsFixed(2)}x',
                          onChanged: (value) {
                            setState(() {
                              _cinematicIntensity = value;
                            });
                          },
                        ),
                      ],
                    ),
                  ),
                ),
                const SizedBox(height: 10),
              ],
              AnimatedSwitcher(
                duration: const Duration(milliseconds: 360),
                switchInCurve: Curves.easeOutCubic,
                switchOutCurve: Curves.easeInCubic,
                transitionBuilder: (child, animation) {
                  return AnimatedBuilder(
                    animation: animation,
                    child: child,
                    builder: (context, c) {
                      final v = Curves.easeOutCubic.transform(animation.value);
                      final transform = Matrix4.identity()
                        ..setEntry(
                            3,
                            2,
                            tier == _MotionTier.low
                                ? 0.0008
                                : tier == _MotionTier.balanced
                                    ? 0.0015
                                    : 0.0023 * cinematicIntensity)
                        ..translate(0.0, (1 - v) * 14, 0.0)
                        ..rotateY((1 - v) *
                            (tier == _MotionTier.low
                                ? 0.15
                                : tier == _MotionTier.balanced
                                    ? 0.34
                                    : 0.5 * cinematicIntensity));
                      return Opacity(
                        opacity: v,
                        child: Transform(
                          alignment: Alignment.center,
                          transform: transform,
                          child: c,
                        ),
                      );
                    },
                  );
                },
                child: Column(
                  key: ValueKey('rapid-grid-$_flipTick-$_rangeFilter'),
                  children: [
                    ...shown.map((index) {
                      final label = (index + 1).toString().padLeft(3, '0');
                      final rarity = _rarityForIndex(index);
                      final isFav = _favoriteIndexes.contains(index);
                      return Padding(
                        padding: const EdgeInsets.only(bottom: 8),
                        child: _ThreeDDeckCard(
                          index: index,
                          tier: tier,
                          cinematicIntensity: cinematicIntensity,
                          styleSeed: _styleSeed,
                          reactionNonce: _reactionNonceByIndex[index] ?? 0,
                          rarity: rarity.rarity,
                          child: Card(
                            color: const Color(0xFF0E1B31),
                            child: Padding(
                              padding: const EdgeInsets.all(10),
                              child: _RapidDeckFlipCard(
                                onTapReact: () {
                                  setState(() {
                                    _reactionNonceByIndex[index] =
                                        (_reactionNonceByIndex[index] ?? 0) + 1;
                                  });
                                },
                                front: Column(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Row(
                                      children: [
                                        const Icon(Icons.auto_awesome,
                                            color: Color(0xFF90E7FF)),
                                        const SizedBox(width: 8),
                                        Expanded(
                                          child: Text(
                                            'Rapid Scenario $label',
                                            style: const TextStyle(
                                              color: Color(0xFFEAF4FF),
                                              fontWeight: FontWeight.w700,
                                            ),
                                          ),
                                        ),
                                        Container(
                                          padding: const EdgeInsets.symmetric(
                                              horizontal: 8, vertical: 3),
                                          decoration: BoxDecoration(
                                            borderRadius:
                                                BorderRadius.circular(999),
                                            color: rarity.color
                                                .withValues(alpha: 0.2),
                                            border: Border.all(
                                              color: rarity.color
                                                  .withValues(alpha: 0.7),
                                            ),
                                          ),
                                          child: Text(
                                            rarity.label,
                                            style: TextStyle(
                                              color: rarity.color,
                                              fontSize: 11,
                                              fontWeight: FontWeight.w700,
                                            ),
                                          ),
                                        ),
                                        IconButton(
                                          onPressed: () {
                                            setState(() {
                                              if (isFav) {
                                                _favoriteIndexes.remove(index);
                                              } else {
                                                _favoriteIndexes.add(index);
                                              }
                                            });
                                          },
                                          icon: Icon(
                                            isFav
                                                ? Icons.star
                                                : Icons.star_border_rounded,
                                            color: isFav
                                                ? const Color(0xFFFFD166)
                                                : const Color(0xFF9FB8D8),
                                          ),
                                          tooltip: isFav
                                              ? 'Remove from favorites'
                                              : 'Add to favorites',
                                        ),
                                      ],
                                    ),
                                    const SizedBox(height: 8),
                                    rapidDeckBuilders[index](),
                                    const SizedBox(height: 6),
                                    const Text(
                                      'Tap for rarity reaction • Double tap to flip',
                                      style: TextStyle(
                                        color: Color(0xFF9CB7D8),
                                        fontSize: 11,
                                      ),
                                    ),
                                  ],
                                ),
                                back: Container(
                                  padding: const EdgeInsets.all(10),
                                  decoration: BoxDecoration(
                                    borderRadius: BorderRadius.circular(12),
                                    gradient: LinearGradient(
                                      begin: Alignment.topLeft,
                                      end: Alignment.bottomRight,
                                      colors: [
                                        const Color(0xFF1A2C4A),
                                        rarity.color.withValues(alpha: 0.3),
                                      ],
                                    ),
                                    border: Border.all(
                                      color: rarity.color.withValues(alpha: 0.6),
                                    ),
                                  ),
                                  child: Column(
                                    crossAxisAlignment:
                                        CrossAxisAlignment.start,
                                    children: [
                                      Text(
                                        'Scenario $label Mission Brief',
                                        style: const TextStyle(
                                          color: Color(0xFFEAF4FF),
                                          fontWeight: FontWeight.w800,
                                          fontSize: 15,
                                        ),
                                      ),
                                      const SizedBox(height: 8),
                                      Text(
                                        'Rarity: ${rarity.label}\n3D Style Variant: ${((index + _styleSeed) % 6) + 1}\nAction Cluster: ${(index % 8) + 1}\nPulse Score: ${((index * 13) % 97) + 3}',
                                        style: const TextStyle(
