                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 12),
          const _SectionTitleReveal(
            title: 'Profile Details',
            delayMs: 230,
          ),
          const SizedBox(height: 6),
          _AnimatedFadeSlide(
