      appBar: AppBar(title: Text(title)),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(20),
          child: Text(
            '$title is ready in navigation.\nNext step is wiring this screen to backend APIs and camera flow.',
            textAlign: TextAlign.center,
          ),
        ),
      ),
    );
  }
}

class FullScreenMapPage extends StatefulWidget {
  final List<String> mapCandidates;
  final int initialIndex;

  const FullScreenMapPage({
    super.key,
    required this.mapCandidates,
    required this.initialIndex,
  });

  @override
  State<FullScreenMapPage> createState() => _FullScreenMapPageState();
}

class _FullScreenMapPageState extends State<FullScreenMapPage> {
  late final WebViewController _controller;
  final Set<Factory<OneSequenceGestureRecognizer>> _mapGestures = {
    Factory<OneSequenceGestureRecognizer>(() => EagerGestureRecognizer()),
  };
  late int _index;
  bool _loading = true;
  String _error = '';

  @override
  void initState() {
    super.initState();
    _index = widget.initialIndex.clamp(0, widget.mapCandidates.length - 1);
    _controller = WebViewController()
      ..setJavaScriptMode(JavaScriptMode.unrestricted)
      ..setBackgroundColor(const Color(0x00000000))
      ..setNavigationDelegate(
        NavigationDelegate(
          onPageStarted: (_) {
            if (!mounted) {
              return;
            }
            setState(() {
              _loading = true;
              _error = '';
            });
          },
          onPageFinished: (_) {
            if (!mounted) {
              return;
            }
            setState(() {
              _loading = false;
            });
          },
          onWebResourceError: (error) {
            if (!mounted) {
              return;
            }
            if (_index + 1 < widget.mapCandidates.length) {
              _index += 1;
              _controller.loadRequest(Uri.parse(widget.mapCandidates[_index]));
              return;
            }
            setState(() {
              _loading = false;
              _error = error.description;
            });
          },
        ),
      )
      ..loadRequest(Uri.parse(widget.mapCandidates[_index]));
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Map Full Screen'),
        actions: [
          IconButton(
            onPressed: () {
              _index = 0;
              _controller.loadRequest(Uri.parse(widget.mapCandidates[_index]));
            },
            icon: const Icon(Icons.refresh),
            tooltip: 'Reload',
          ),
        ],
      ),
      body: Stack(
        children: [
          Positioned.fill(
            child: WebViewWidget(
              controller: _controller,
              gestureRecognizers: _mapGestures,
            ),
          ),
          if (_loading)
            const Positioned.fill(
              child: Center(child: CircularProgressIndicator()),
            ),
          if (_error.isNotEmpty)
            Positioned.fill(
              child: Container(
                color: const Color(0xCC11182A),
                alignment: Alignment.center,
                padding: const EdgeInsets.all(12),
                child: Text(
                  'Map load error: $_error',
                  textAlign: TextAlign.center,
                  style: const TextStyle(color: Colors.white),
                ),
              ),
            ),
        ],
      ),
    );
  }
}


class RapidScenario {
  final String title;
  final String subtitle;
  final IconData icon;
  final Color color;
  const RapidScenario({
    required this.title,
    required this.subtitle,
    required this.icon,
    required this.color,
  });
}

class RapidScenarioTile extends StatelessWidget {
  final RapidScenario scenario;
  final double scale;
  const RapidScenarioTile({
    super.key,
    required this.scenario,
    this.scale = 1,
  });

  @override
  Widget build(BuildContext context) {
    final cardColor = Color.alphaBlend(
      scenario.color.withValues(alpha: 0.16),
      Theme.of(context).colorScheme.surface,
    );
    return Transform.scale(
      scale: scale,
      child: Card(
        color: cardColor,
        child: ListTile(
          leading: Icon(scenario.icon, color: scenario.color),
          title: Text(scenario.title),
          subtitle: Text(scenario.subtitle),
        ),
      ),
    );
  }
}

class RapidDeckWidget001 extends StatelessWidget {
  const RapidDeckWidget001({super.key});

  @override
  Widget build(BuildContext context) {
    final scenario = RapidScenario(
      title: 'Rapid Scenario 001',
      subtitle: 'Operational profile and animated cue set 001',
      icon: Icons.auto_awesome,
      color: const Color(0xFF6FD3FF),
    );
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0.96, end: 1),
      duration: const Duration(milliseconds: 260),
      curve: Curves.easeOutCubic,
      builder: (context, value, child) {
        return Opacity(opacity: value.clamp(0, 1), child: child);
      },
      child: RapidScenarioTile(scenario: scenario, scale: 1),
    );
  }
}

