  @override
  Widget build(BuildContext context) {
    final scenario = RapidScenario(
      title: 'Rapid Scenario 183',
      subtitle: 'Operational profile and animated cue set 183',
      icon: Icons.auto_awesome,
      color: const Color(0xFF6FD3FF),
    );
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0.96, end: 1),
      duration: const Duration(milliseconds: 260),
      curve: Curves.easeOutCubic,
      builder: (context, value, child) {
        return Opacity(opacity: value.clamp(0, 1), child: child);
      },
      child: RapidScenarioTile(scenario: scenario, scale: 1),
    );
  }
}

