class Inline3DFeatureModel {
  final String code;
  final String title;
  final String subtitle;
  final IconData icon;
  final Color tone;
  const Inline3DFeatureModel({
    required this.code,
    required this.title,
    required this.subtitle,
    required this.icon,
    required this.tone,
  });
}

class Inline3DFeatureTile extends StatefulWidget {
  final Inline3DFeatureModel model;
  const Inline3DFeatureTile({super.key, required this.model});

  @override
  State<Inline3DFeatureTile> createState() => _Inline3DFeatureTileState();
}

class _Inline3DFeatureTileState extends State<Inline3DFeatureTile> {
  double _rx = 0;
  double _ry = 0;

  void _onHover(Offset local, Size size) {
    if (size.width <= 0 || size.height <= 0) return;
    final nx = ((local.dx / size.width) - 0.5).clamp(-0.5, 0.5);
    final ny = ((local.dy / size.height) - 0.5).clamp(-0.5, 0.5);
    setState(() {
      _ry = nx * 0.22;
      _rx = -ny * 0.22;
    });
  }

  void _reset() {
    if (_rx == 0 && _ry == 0) return;
    setState(() {
      _rx = 0;
      _ry = 0;
    });
  }

  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(
      builder: (context, constraints) {
        final size = Size(
          constraints.maxWidth.isFinite ? constraints.maxWidth : 1,
          constraints.maxHeight.isFinite ? constraints.maxHeight : 1,
        );
        return MouseRegion(
          onHover: (event) => _onHover(event.localPosition, size),
          onExit: (_) => _reset(),
          child: GestureDetector(
            behavior: HitTestBehavior.translucent,
            onPanUpdate: (details) => _onHover(details.localPosition, size),
            onPanEnd: (_) => _reset(),
            onPanCancel: _reset,
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 140),
              curve: Curves.easeOutCubic,
              transform: Matrix4.identity()
                ..setEntry(3, 2, 0.0018)
                ..rotateX(_rx)
                ..rotateY(_ry),
              child: Card(
                color: Color.alphaBlend(
                  widget.model.tone.withValues(alpha: 0.14),
                  Theme.of(context).colorScheme.surface,
                ),
                child: ListTile(
                  leading: Icon(widget.model.icon, color: widget.model.tone),
                  title: Text(widget.model.title),
                  subtitle: Text(widget.model.subtitle),
                ),
              ),
            ),
          ),
        );
      },
    );
  }
}

class Inline3DFeatureCard001 extends StatelessWidget {
  const Inline3DFeatureCard001({super.key});

  @override
  Widget build(BuildContext context) {
    const model = Inline3DFeatureModel(
      code: '001',
      title: 'Inline 3D Feature 001',
      subtitle: 'In-file 3D animation block and feature tile set',
      icon: Icons.view_in_ar,
      tone: Color(0xFF74D9FF),
    );
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0.9, end: 1),
      duration: const Duration(milliseconds: 210),
      curve: Curves.easeOutCubic,
      builder: (context, t, child) {
        return Transform.scale(scale: t, child: Opacity(opacity: t, child: child));
      },
      child: const Inline3DFeatureTile(model: model),
    );
  }
}

